frappe.ui.form.on('Checklist Run', {
    checklist_template: function(frm) {
        if (frm.doc.checklist_template) {
            // Fetch the template
            frappe.call({
                method: 'frappe.client.get',
                args: {
                    doctype: 'Checklist Template',
                    name: frm.doc.checklist_template
                },
                callback: function(r) {
                    if (r.message) {
                        var template = r.message;

                        // Fill template info
                        frm.set_value('template_name', template.template_name);
                        frm.set_value('version', template.version);
                        frm.set_value('requires_approval', template.requires_approval);
                        frm.set_value('department', template.department);

                        // Set started by if empty
                        if (!frm.doc.started_by) {
                            frm.set_value('started_by', frappe.session.user);
                        }

                        // Set start date if empty
                        if (!frm.doc.start_date) {
                            frm.set_value('start_date', frappe.datetime.get_today());
                        }

                        // Copy template items to run items
                        if (template.items && template.items.length > 0) {
                            frm.clear_table('items');

                            template.items.forEach(function(item) {
                                var child = frm.add_child('items');
                                child.step_no = item.step_no;
                                child.step_title = item.step_title;
                                child.mandatory = item.mandatory;
                            });

                            frm.refresh_field('items');
                        }
                    }
                }
            });
        }
    },

    onload: function(frm) {
        // Set status to Draft on load if new
        if (frm.is_new()) {
            frm.set_value('status', 'Draft');
        }
    }
});

// Update status when items are completed
frappe.ui.form.on('Checklist Run Item', {
    completed: function(frm, cdt, cdn) {
        update_status_based_on_items(frm);
    }
});

function update_status_based_on_items(frm) {
    if (frm.doc.items && frm.doc.items.length > 0) {
        var all_completed = true;
        var any_mandatory_incomplete = false;

        frm.doc.items.forEach(function(item) {
            if (item.mandatory && !item.completed) {
                any_mandatory_incomplete = true;
            }
            if (!item.completed) {
                all_completed = false;
            }
        });

        // Auto-update status based on completion
        if (all_completed && !any_mandatory_incomplete) {
            if (frm.doc.status === 'Draft' || frm.doc.status === 'In Progress') {
                frm.set_value('status', 'In Progress');
            }
        }

        // Set completed date when all items are done
        if (all_completed && !any_mandatory_incomplete) {
            frm.set_value('completed_date', frappe.datetime.get_today());
        }
    }
}
